    private async Task<IActionResult> UploadFile(IFormFile file, string fileType, long maxFileSize)
    {
        if (file == null || file.Length == 0)
        {
            return BadRequest(new { error = "No file uploaded" });
        }

        if (file.Length > maxFileSize)
        {
            return BadRequest(new { error = $"File size exceeds maximum allowed size of {maxFileSize / (1024 * 1024)} MB" });
        }

        var extension = Path.GetExtension(file.FileName).ToLowerInvariant();

        if (string.IsNullOrEmpty(extension))
        {
            return BadRequest(new { error = "File has no extension" });
        }

        if (!AllowedFileTypes.ContainsKey(fileType) || !AllowedFileTypes[fileType].Contains(extension))
        {
            return BadRequest(new { error = $"File type {extension} is not allowed for {fileType}" });
        }

        var isValidSignature = await ValidateFileSignature(file, extension);
        if (!isValidSignature)
        {
            return BadRequest(new { error = "File content does not match its extension" });
        }

        var sanitizedFileName = SanitizeFileName(Path.GetFileNameWithoutExtension(file.FileName));
        var uniqueFileName = $"{sanitizedFileName}_{Guid.NewGuid()}{extension}";
        
        var typeFolder = Path.Combine(_uploadPath, fileType);
        if (!Directory.Exists(typeFolder))
        {
            Directory.CreateDirectory(typeFolder);
        }

        var filePath = Path.Combine(typeFolder, uniqueFileName);

        try
        {
            using (var stream = new FileStream(filePath, FileMode.Create, FileAccess.Write, FileShare.None, 4096, useAsync: true))
            {
                await file.CopyToAsync(stream);
            }

            var relativePath = $"/uploads/{fileType}/{uniqueFileName}";
            
            return Ok(new
            {
                fileName = uniqueFileName,
                filePath = relativePath,
                fileSize = file.Length,
                fileType = fileType,
                uploadedAt = DateTime.UtcNow
            });
        }
        catch (Exception ex)
        {
            if (System.IO.File.Exists(filePath))
            {
                System.IO.File.Delete(filePath);
            }
            
            return StatusCode(500, new { error = "An error occurred while uploading the file" });
        }
    }

    private async Task<bool> ValidateFileSignature(IFormFile file, string extension)
    {
        if (!FileSignatures.ContainsKey(extension))
        {
            return true;
        }

        var signatures = FileSignatures[extension];
        var headerBytes = new byte[8];
        
        using (var stream = file.OpenReadStream())
        {
            var bytesRead = await stream.ReadAsync(headerBytes, 0, headerBytes.Length);
            
            if (bytesRead == 0)
            {
                return false;
            }

            foreach (var signature in signatures)
            {
                if (headerBytes.Take(signature.Length).SequenceEqual(signature))
                {
                    return true;
                }
            }
        }

        return false;
    }

    private string SanitizeFileName(string fileName)
    {
        var invalidChars = Path.GetInvalidFileNameChars();
        var sanitized = string.Join("_", fileName.Split(invalidChars, StringSplitOptions.RemoveEmptyEntries));
        
        sanitized = sanitized.Replace(" ", "_");
        
        if (sanitized.Length > 50)
        {
            sanitized = sanitized.Substring(0, 50);
        }

        return string.IsNullOrWhiteSpace(sanitized) ? "file" : sanitized;
    }

    [HttpDelete("{fileType}/{fileName}")]
    public IActionResult DeleteFile(string fileType, string fileName)
    {
        if (!AllowedFileTypes.ContainsKey(fileType))
        {
            return BadRequest(new { error = "Invalid file type" });
        }

        var sanitizedFileName = Path.GetFileName(fileName);
        var filePath = Path.Combine(_uploadPath, fileType, sanitizedFileName);

        if (!System.IO.File.Exists(filePath))
        {
            return NotFound(new { error = "File not found" });
        }

        try
        {
            System.IO.File.Delete(filePath);
            return Ok(new { message = "File deleted successfully" });
        }
        catch (Exception ex)
        {
            return StatusCode(500, new { error = "An error occurred while deleting the file" });
        }
    }
